content.text:
C++11-də təqdim edilən `enum class` (scoped enum) adi enumlara nisbətən daha təhlükəsizdir, çünki dəyərlər ad məkanı ilə məhdudlaşdırılır və avtomatik tam ədədə çevrilmir. Sintaksis aşağıdakı kimidir:
enum class EnumName { value1, value2, value3 };
Scoped enumlar dəyərlərə müraciət etmək üçün `EnumName::value` formasını tələb edir.

content.code:
#include <iostream>

enum class Color { RED, GREEN, BLUE };

int main() {
  Color color = Color::GREEN;
  std::cout << "Color value: " << static_cast<int>(color) << std::endl;
  return 0;
}
// Output:
// Color value: 1

#include <iostream>
#include <string>

enum class Day { MONDAY, TUESDAY, WEDNESDAY };

void printDay(Day day) {
  if (day == Day::MONDAY) {
    std::cout << "Today is Monday" << std::endl;
  } else if (day == Day::TUESDAY) {
    std::cout << "Today is Tuesday" << std::endl;
  } else {
    std::cout << "Today is Wednesday" << std::endl;
  }
}

int main() {
  Day day = Day::TUESDAY;
  printDay(day);
  return 0;
}
// Output:
// Today is Tuesday

#include <iostream>
#include <string>

enum class Status { ACTIVE, INACTIVE };

struct User {
  std::string name;
  Status status;
};

int main() {
  User user;
  user.name = "Ali";
  user.status = Status::ACTIVE;
  std::cout << "Name: " << user.name << std::endl;
  std::cout << "Status: " << (user.status == Status::ACTIVE ? "Active" : "Inactive") << std::endl;
  return 0;
}
// Output:
// Name: Ali
// Status: Active

